// Write a method that transposes a square n×n matrix in-place.
// The transpose swaps mat[i][j] with mat[j][i] for all i < j.
// Print the matrix after transposing.
// Example input matrix:
// 1 2 3
// 4 5 6
// 7 8 9
// Expected output after transpose:
// 1 4 7
// 2 5 8
// 3 6 9

sections.solution:
public class Transpose {
    static void transpose(int[][] mat) {
        int n = mat.length;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int temp = mat[i][j];
                mat[i][j] = mat[j][i];
                mat[j][i] = temp;
            }
        }
    }

    static void printMatrix(int[][] mat) {
        for (int[] row : mat) {
            for (int val : row)
                System.out.printf("%3d", val);
            System.out.println();
        }
    }

    public static void main(String[] args) {
        int[][] mat = {
            {1, 2, 3},
            {4, 5, 6},
            {7, 8, 9}
        };
        transpose(mat);
        printMatrix(mat);
    }
}
